+private final class LiveDictationSessionTrace: DictationSessionTracing {
+    private let sessionID = UUID()
+    private let dateProvider: any DateProviding
+    private let logger: any PerformanceTraceLogging
+
+    private var microphoneLiveAt: Date?
+    private var hotkeyLiftedAt: Date?
+    private var microphoneColdAt: Date?
+    private var transcriptionStartAt: Date?
+    private var pasteStartAt: Date?
+    private var pasteEndAt: Date?
+    private var didComplete = false
+
+    init(
+        dateProvider: any DateProviding,
+        logger: any PerformanceTraceLogging
+    ) {
+        self.dateProvider = dateProvider
+        self.logger = logger
+    }
+
+    func markMicrophoneLive() {
+        microphoneLiveAt = dateProvider.currentDate()
+    }
+
+    func markHotkeyLifted() {
+        hotkeyLiftedAt = dateProvider.currentDate()
+    }
+
+    func markMicrophoneCold() {
+        microphoneColdAt = dateProvider.currentDate()
+    }
+
+    func markTranscriptionStart() {
+        transcriptionStartAt = dateProvider.currentDate()
+    }
+
+    func markPasteStart() {
+        pasteStartAt = dateProvider.currentDate()
+    }
+
+    func markPasteEnd() {
+        guard !didComplete else {
+            return
+        }
+
+        pasteEndAt = dateProvider.currentDate()
+        didComplete = true
+        logger.logPerformance(summaryLine())
+    }
+
+    func abandon() {
+        didComplete = true
+    }
+
+    private func summaryLine() -> String {
+        var components = ["session=\(sessionID.uuidString)"]
+
+        if let duration = durationMilliseconds(from: hotkeyLiftedAt, to: microphoneColdAt) {
+            components.append("hotkey_lift_to_mic_cold=\(duration)ms")
+        }
+
+        if let duration = durationMilliseconds(from: transcriptionStartAt, to: pasteStartAt ?? pasteEndAt) {
+            components.append("transcription=\(duration)ms")
+        }
+
+        if let duration = durationMilliseconds(from: pasteStartAt, to: pasteEndAt) {
+            components.append("paste=\(duration)ms")
+        }
+
+        if let duration = durationMilliseconds(from: microphoneLiveAt, to: pasteEndAt) {
+            components.append("total=\(duration)ms")
+        }
+
+        return components.joined(separator: " ")
+    }
+
+    private func durationMilliseconds(from start: Date?, to end: Date?) -> Int? {
+        guard let start, let end else {
+            return nil
+        }
+
+        return Int(((end.timeIntervalSince(start)) * 1_000.0).rounded())
+    }
+}

