+import Foundation
+
+struct PostPasteLearningObservation: Equatable, Sendable {
+    let pastedText: String
+    let focusedElementText: String?
+    let correctionDetected: Bool
+}
+
+protocol PostPasteLearningCoordinating: AnyObject {
+    func recordPaste(_ snapshot: PasteSessionSnapshot)
+}
+
+final class NoOpPostPasteLearningCoordinator: PostPasteLearningCoordinating {
+    func recordPaste(_ snapshot: PasteSessionSnapshot) {
+        _ = snapshot
+    }
+}
+
+final class SimplePostPasteLearningCoordinator: PostPasteLearningCoordinating {
+    private(set) var observations: [PostPasteLearningObservation] = []
+
+    func recordPaste(_ snapshot: PasteSessionSnapshot) {
+        let normalizedFocusedText = snapshot.focusedElementText?
+            .trimmingCharacters(in: .whitespacesAndNewlines)
+        let correctionDetected: Bool
+        if let normalizedFocusedText, !normalizedFocusedText.isEmpty {
+            correctionDetected = normalizedFocusedText != snapshot.pastedText
+        } else {
+            correctionDetected = false
+        }
+
+        observations.append(
+            PostPasteLearningObservation(
+                pastedText: snapshot.pastedText,
+                focusedElementText: snapshot.focusedElementText,
+                correctionDetected: correctionDetected
+            )
+        )
+    }
+}

